import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import Swal from 'sweetalert2';

const Navbar = () =>
{
    const navigate = useNavigate();

    const logoutSubmit = (e) =>
    {
        e.preventDefault();

        axios.post('/api/logout').then(res =>
        {
            if (res.data.status === 200)
            {
                localStorage.removeItem('auth_token');
                localStorage.removeItem('auth_name');
                Swal.fire({
                    title: "Logged Out",
                    text: res.data.message,
                    icon: "success",
                    timer: 1500,
                    showConfirmButton: false,
                });
                navigate('/login');
            }
        });
    }

    const authName = localStorage.getItem('auth_name');

    return (
        <nav className="sb-topnav navbar navbar-expand navbar-dark bg-dark">
            <Link className="navbar-brand ps-3" to="/admin">Admin Panel</Link>
            {/* <!-- Sidebar Toggle--> */}
            <button className="btn btn-link btn-sm order-1 order-lg-0 me-4 me-lg-0" id="sidebarToggle">
                <i className="fas fa-bars"></i></button>

            <form className="d-none d-md-inline-block form-inline ms-auto me-0 me-md-3 my-2 my-md-0">
                {/* Search form can go here if needed */}
            </form>

            <ul className="navbar-nav ms-auto ms-md-0 me-3 me-lg-4">
                <li className="nav-item dropdown">
                    <Link className="nav-link dropdown-toggle" id="navbarDropdown" to="#" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                        <i className="fas fa-user fa-fw"></i> {authName || 'User'}
                    </Link>
                    <ul className="dropdown-menu dropdown-menu-end" aria-labelledby="navbarDropdown">
                        <li><Link className="dropdown-item" to="/admin/profile">Profile</Link></li>
                        <li><hr className="dropdown-divider" /></li>
                        <li><button type="button" onClick={logoutSubmit} className="dropdown-item">Logout</button></li>
                    </ul>
                </li>
            </ul>
        </nav>
    );
}

export default Navbar;
